# Fleet runs this uninstall script as SYSTEM (machine scope).
# Match against the registry DisplayName for Podman Desktop.
$softwareName = "Podman Desktop"

# It is recommended to use exact software name here if possible to avoid
# uninstalling unintended software.
$softwareNameLike = "*$softwareName*"

# NSIS (Nullsoft) uninstaller silent flag (used if UninstallString carries none).
$defaultArgs = "/S"

# Podman Desktop is an Electron app. Under machine scope it registers its ARP
# entry in HKLM, but it can also register per-user under HKCU (the registry
# DisplayName carries a trailing version, e.g. "Podman Desktop 1.27.2", which the
# wildcard match above handles). Search both hives.
$paths = @(
  'HKLM:\SOFTWARE\Microsoft\Windows\CurrentVersion\Uninstall\*',
  'HKLM:\SOFTWARE\WOW6432Node\Microsoft\Windows\CurrentVersion\Uninstall\*',
  'HKCU:\SOFTWARE\Microsoft\Windows\CurrentVersion\Uninstall\*',
  'HKCU:\SOFTWARE\WOW6432Node\Microsoft\Windows\CurrentVersion\Uninstall\*'
)

$exitCode = 0

try {

[array]$uninstallKeys = Get-ChildItem `
    -Path $paths `
    -ErrorAction SilentlyContinue |
        ForEach-Object { Get-ItemProperty $_.PSPath }

$foundUninstaller = $false
foreach ($key in $uninstallKeys) {
    if ($key.DisplayName -like $softwareNameLike) {
        $foundUninstaller = $true

        # Prefer QuietUninstallString when present; it already includes silent flags.
        $useQuiet = [bool]$key.QuietUninstallString
        $uninstallCommand = if ($useQuiet) {
            $key.QuietUninstallString
        } else {
            $key.UninstallString
        }

        if ([string]::IsNullOrWhiteSpace($uninstallCommand)) {
            Throw "No UninstallString found for '$($key.DisplayName)'."
        }

        # Parse the UninstallString defensively. It comes in three shapes:
        #   1. "C:\Path With Spaces\Uninstall Podman Desktop.exe" /S  (quoted)
        #   2. C:\Path With Spaces\Uninstall.exe /S                   (unquoted, may contain spaces)
        #   3. MsiExec.exe /X{GUID}                                   (bare token)
        if ($uninstallCommand -match '^\s*"([^"]+)"\s*(.*)$') {
            $exe = $matches[1]
            $args = $matches[2].Trim()
        } elseif ($uninstallCommand -match '(?i)^\s*(.+?\.exe)\s*(.*)$') {
            $exe = $matches[1]
            $args = $matches[2].Trim()
        } else {
            $uninstallCommand -match '^\s*(\S+)\s*(.*)$' | Out-Null
            $exe = $matches[1]
            $args = $matches[2].Trim()
        }

        # If we fell back to the raw UninstallString (no quiet variant), make sure
        # the silent flag is present.
        if (-not $useQuiet -and ($args -notmatch '(?i)\b/S\b')) {
            $args = "$args $defaultArgs".Trim()
        }

        Write-Host "Uninstall command: $exe"
        Write-Host "Uninstall args: $args"

        $processOptions = @{
            FilePath = $exe
            PassThru = $true
            Wait = $true
        }
        if ($args -ne '') {
            $processOptions.ArgumentList = $args
        }

        $process = Start-Process @processOptions
        $exitCode = $process.ExitCode
        Write-Host "Uninstall exit code: $exitCode"
        break
    }
}

if (-not $foundUninstaller) {
    Write-Host "Uninstaller for '$softwareName' not found."
    $exitCode = 1
}

} catch {
    Write-Host "Error: $_"
    $exitCode = 1
}

Exit $exitCode
